import{_ as s,c as a,o as n,a as e}from"./app.80007782.js";const C=JSON.parse(`{"title":"\u{1F527} Troubleshooting","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F433} Docker Swarm Issues","slug":"\u{1F433}-docker-swarm-issues","link":"#\u{1F433}-docker-swarm-issues","children":[{"level":3,"title":"Service Won't Start or Keeps Restarting","slug":"service-won-t-start-or-keeps-restarting","link":"#service-won-t-start-or-keeps-restarting","children":[]},{"level":3,"title":"Registry Connection Issues","slug":"registry-connection-issues","link":"#registry-connection-issues","children":[]}]},{"level":2,"title":"\u{1F4BE} Database Issues","slug":"\u{1F4BE}-database-issues","link":"#\u{1F4BE}-database-issues","children":[{"level":3,"title":"Connection Failures","slug":"connection-failures","link":"#connection-failures","children":[]},{"level":3,"title":"Migration Errors","slug":"migration-errors","link":"#migration-errors","children":[]}]},{"level":2,"title":"\u{1F512} Authentication Issues","slug":"\u{1F512}-authentication-issues","link":"#\u{1F512}-authentication-issues","children":[{"level":3,"title":"JWT Validation Fails","slug":"jwt-validation-fails","link":"#jwt-validation-fails","children":[]},{"level":3,"title":"Firebase Authentication Issues","slug":"firebase-authentication-issues","link":"#firebase-authentication-issues","children":[]}]},{"level":2,"title":"\u{1F310} Network Issues","slug":"\u{1F310}-network-issues","link":"#\u{1F310}-network-issues","children":[{"level":3,"title":"Nginx Configuration Problems","slug":"nginx-configuration-problems","link":"#nginx-configuration-problems","children":[]},{"level":3,"title":"CORS Issues","slug":"cors-issues","link":"#cors-issues","children":[]}]},{"level":2,"title":"\u{1F4BB} Frontend Issues","slug":"\u{1F4BB}-frontend-issues","link":"#\u{1F4BB}-frontend-issues","children":[{"level":3,"title":"Build Failures","slug":"build-failures","link":"#build-failures","children":[]},{"level":3,"title":"API Connection Issues","slug":"api-connection-issues","link":"#api-connection-issues","children":[]}]},{"level":2,"title":"\u{1F4CA} Monitoring Issues","slug":"\u{1F4CA}-monitoring-issues","link":"#\u{1F4CA}-monitoring-issues","children":[{"level":3,"title":"Prometheus/Grafana Connection Problems","slug":"prometheus-grafana-connection-problems","link":"#prometheus-grafana-connection-problems","children":[]}]},{"level":2,"title":"\u{1F680} Deployment Script Issues","slug":"\u{1F680}-deployment-script-issues","link":"#\u{1F680}-deployment-script-issues","children":[{"level":3,"title":"Build and Deploy Script Fails","slug":"build-and-deploy-script-fails","link":"#build-and-deploy-script-fails","children":[]}]},{"level":2,"title":"\u{1F321}\uFE0F Performance Issues","slug":"\u{1F321}\uFE0F-performance-issues","link":"#\u{1F321}\uFE0F-performance-issues","children":[{"level":3,"title":"Slow Application Response","slug":"slow-application-response","link":"#slow-application-response","children":[]}]},{"level":2,"title":"\u{1F9EA} Development Environment Issues","slug":"\u{1F9EA}-development-environment-issues","link":"#\u{1F9EA}-development-environment-issues","children":[{"level":3,"title":"Hot Reload Not Working","slug":"hot-reload-not-working","link":"#hot-reload-not-working","children":[]}]},{"level":2,"title":"\u{1F4D1} Logs and Diagnostics","slug":"\u{1F4D1}-logs-and-diagnostics","link":"#\u{1F4D1}-logs-and-diagnostics","children":[{"level":3,"title":"Collecting Diagnostic Information","slug":"collecting-diagnostic-information","link":"#collecting-diagnostic-information","children":[]}]},{"level":2,"title":"\u{1F4DE} Getting Help","slug":"\u{1F4DE}-getting-help","link":"#\u{1F4DE}-getting-help","children":[]}],"relativePath":"bg/setup/troubleshooting.md","lastUpdated":1744659307000}`),l={name:"bg/setup/troubleshooting.md"},o=e(`<h1 id="\u{1F527}-troubleshooting" tabindex="-1">\u{1F527} Troubleshooting <a class="header-anchor" href="#\u{1F527}-troubleshooting" aria-hidden="true">#</a></h1><p>This guide provides solutions to common issues you might encounter when setting up or running UniTrack.</p><h2 id="\u{1F433}-docker-swarm-issues" tabindex="-1">\u{1F433} Docker Swarm Issues <a class="header-anchor" href="#\u{1F433}-docker-swarm-issues" aria-hidden="true">#</a></h2><h3 id="service-won-t-start-or-keeps-restarting" tabindex="-1">Service Won&#39;t Start or Keeps Restarting <a class="header-anchor" href="#service-won-t-start-or-keeps-restarting" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Services show <code>0/1</code> replicas in <code>docker stack services</code></li><li>Containers constantly restart</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check container logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service logs unitrack-stack_unitrack-backend</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify resource constraints:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker info </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep Resources</span></span>
<span class="line"></span></code></pre></div><p>Make sure your host has enough memory and CPU.</p></li><li><p>Check for port conflicts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">netstat -tuln</span></span>
<span class="line"></span></code></pre></div><p>Ensure ports 5432, 5086, 3000, 8080, 9090, and 3001 are not in use by other applications.</p></li><li><p>Restart Docker:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">systemctl restart docker</span></span>
<span class="line"></span></code></pre></div></li></ol><h3 id="registry-connection-issues" tabindex="-1">Registry Connection Issues <a class="header-anchor" href="#registry-connection-issues" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>no basic auth credentials</code> error</li><li><code>unauthorized: authentication required</code> error</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Verify the registry is running:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker ps </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep registry</span></span>
<span class="line"></span></code></pre></div></li><li><p>Check if you can push to the registry:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker tag hello-world localhost:5000/hello-world</span></span>
<span class="line"><span style="color:#A6ACCD;">docker push localhost:5000/hello-world</span></span>
<span class="line"></span></code></pre></div></li><li><p>Restart the registry:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker restart registry</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F4BE}-database-issues" tabindex="-1">\u{1F4BE} Database Issues <a class="header-anchor" href="#\u{1F4BE}-database-issues" aria-hidden="true">#</a></h2><h3 id="connection-failures" tabindex="-1">Connection Failures <a class="header-anchor" href="#connection-failures" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>Connection refused</code> errors in backend logs</li><li><code>Unable to connect to PostgreSQL</code> errors</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check if PostgreSQL is running:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker ps </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep postgres</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify PostgreSQL logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker logs UniTrackRemaster.Database</span></span>
<span class="line"></span></code></pre></div></li><li><p>Test the connection:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Database psql -U postgres -d UniTrackRemaster -c </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">SELECT 1</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div></li><li><p>Recreate the database container:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker rm -f UniTrackRemaster.Database</span></span>
<span class="line"><span style="color:#A6ACCD;">docker stack deploy -c docker-compose.yml unitrack-stack</span></span>
<span class="line"></span></code></pre></div></li></ol><h3 id="migration-errors" tabindex="-1">Migration Errors <a class="header-anchor" href="#migration-errors" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>Migration failed</code> errors</li><li>Database schema errors in logs</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Reset the database (\u26A0\uFE0F will lose data):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Database psql -U postgres -c </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">DROP DATABASE </span><span style="color:#A6ACCD;">\\&quot;</span><span style="color:#C3E88D;">UniTrackRemaster</span><span style="color:#A6ACCD;">\\&quot;</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Database psql -U postgres -c </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">CREATE DATABASE </span><span style="color:#A6ACCD;">\\&quot;</span><span style="color:#C3E88D;">UniTrackRemaster</span><span style="color:#A6ACCD;">\\&quot;</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div></li><li><p>Apply migrations manually:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend dotnet ef database update</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F512}-authentication-issues" tabindex="-1">\u{1F512} Authentication Issues <a class="header-anchor" href="#\u{1F512}-authentication-issues" aria-hidden="true">#</a></h2><h3 id="jwt-validation-fails" tabindex="-1">JWT Validation Fails <a class="header-anchor" href="#jwt-validation-fails" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>Invalid token</code> errors</li><li>Users can&#39;t log in</li><li><code>401 Unauthorized</code> responses</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check JWT configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend cat /app/appsettings.json </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep JWT</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify that JWT secret is properly set in environment:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend printenv </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep JWT</span></span>
<span class="line"></span></code></pre></div></li><li><p>Clear browser cookies and local storage</p></li></ol><h3 id="firebase-authentication-issues" tabindex="-1">Firebase Authentication Issues <a class="header-anchor" href="#firebase-authentication-issues" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Push notifications not working</li><li>Firebase-related errors in logs</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Verify Firebase credentials:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend ls -la /run/secrets/</span></span>
<span class="line"></span></code></pre></div></li><li><p>Check if the credentials file is mounted correctly:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend cat /run/secrets/firebase_credentials </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> head -5</span></span>
<span class="line"></span></code></pre></div></li><li><p>Update Firebase credentials and redeploy</p></li></ol><h2 id="\u{1F310}-network-issues" tabindex="-1">\u{1F310} Network Issues <a class="header-anchor" href="#\u{1F310}-network-issues" aria-hidden="true">#</a></h2><h3 id="nginx-configuration-problems" tabindex="-1">Nginx Configuration Problems <a class="header-anchor" href="#nginx-configuration-problems" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>502 Bad Gateway</code> errors</li><li><code>Connection refused</code> when accessing frontend</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check Nginx configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.LoadBalancer nginx -t</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify Nginx logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.LoadBalancer cat /var/log/nginx/error.log</span></span>
<span class="line"></span></code></pre></div></li><li><p>Test backend connectivity from Nginx:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.LoadBalancer curl unitrack-backend:5086/health</span></span>
<span class="line"></span></code></pre></div></li><li><p>Restart Nginx:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.LoadBalancer nginx -s reload</span></span>
<span class="line"></span></code></pre></div></li></ol><h3 id="cors-issues" tabindex="-1">CORS Issues <a class="header-anchor" href="#cors-issues" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Browser console errors about CORS</li><li>API requests fail in frontend but work in tools like Postman</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check backend CORS configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Backend cat /app/appsettings.json </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep -A 10 CORS</span></span>
<span class="line"></span></code></pre></div></li><li><p>Update CORS settings in environment variables:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki"><code><span class="line"><span style="color:#F07178;">environment</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">CORS__AllowedOrigins=https://your-domain.com,http://localhost:3000</span></span>
<span class="line"></span></code></pre></div></li><li><p>Restart the backend service:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service update --force unitrack-stack_unitrack-backend</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F4BB}-frontend-issues" tabindex="-1">\u{1F4BB} Frontend Issues <a class="header-anchor" href="#\u{1F4BB}-frontend-issues" aria-hidden="true">#</a></h2><h3 id="build-failures" tabindex="-1">Build Failures <a class="header-anchor" href="#build-failures" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li><code>Failed to compile</code> errors</li><li>White screen in browser</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check frontend build logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service logs unitrack-stack_unitrack-frontend</span></span>
<span class="line"></span></code></pre></div></li><li><p>Clean node_modules and rebuild:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> UniTrackRemasterFrontend</span></span>
<span class="line"><span style="color:#A6ACCD;">rm -rf node_modules</span></span>
<span class="line"><span style="color:#A6ACCD;">npm install</span></span>
<span class="line"><span style="color:#A6ACCD;">npm run build</span></span>
<span class="line"></span></code></pre></div></li><li><p>Rebuild frontend image:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker build -t localhost:5000/unitrack-frontend:latest ./UniTrackRemasterFrontend</span></span>
<span class="line"><span style="color:#A6ACCD;">docker push localhost:5000/unitrack-frontend:latest</span></span>
<span class="line"><span style="color:#A6ACCD;">docker service update --force unitrack-stack_unitrack-frontend</span></span>
<span class="line"></span></code></pre></div></li></ol><h3 id="api-connection-issues" tabindex="-1">API Connection Issues <a class="header-anchor" href="#api-connection-issues" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>&quot;Failed to fetch&quot; errors in console</li><li>API requests timing out</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Verify API URL configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Frontend env </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> grep API_BASE_URL</span></span>
<span class="line"></span></code></pre></div></li><li><p>Test API connectivity:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">curl -I http://localhost:5086/health</span></span>
<span class="line"></span></code></pre></div></li><li><p>Update the API base URL environment variable:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki"><code><span class="line"><span style="color:#F07178;">environment</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">NUXT_PUBLIC_API_BASE_URL=http://unitrack-backend:5086</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F4CA}-monitoring-issues" tabindex="-1">\u{1F4CA} Monitoring Issues <a class="header-anchor" href="#\u{1F4CA}-monitoring-issues" aria-hidden="true">#</a></h2><h3 id="prometheus-grafana-connection-problems" tabindex="-1">Prometheus/Grafana Connection Problems <a class="header-anchor" href="#prometheus-grafana-connection-problems" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>No data in Grafana dashboards</li><li>&quot;No data points&quot; errors</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check Prometheus configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Prometheus cat /etc/prometheus/prometheus.yml</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify Prometheus can scrape targets:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">curl http://localhost:9090/api/v1/targets</span></span>
<span class="line"></span></code></pre></div></li><li><p>Test metrics endpoint:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">curl http://unitrack-backend:5086/metrics</span></span>
<span class="line"></span></code></pre></div></li><li><p>Restart monitoring services:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service update --force unitrack-stack_prometheus</span></span>
<span class="line"><span style="color:#A6ACCD;">docker service update --force unitrack-stack_grafana</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F680}-deployment-script-issues" tabindex="-1">\u{1F680} Deployment Script Issues <a class="header-anchor" href="#\u{1F680}-deployment-script-issues" aria-hidden="true">#</a></h2><h3 id="build-and-deploy-script-fails" tabindex="-1">Build and Deploy Script Fails <a class="header-anchor" href="#build-and-deploy-script-fails" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Script exits with error</li><li>Images not being pushed to registry</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Run script with debugging:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">bash -x build_and_deploy.sh</span></span>
<span class="line"></span></code></pre></div></li><li><p>Check Docker daemon status:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">systemctl status docker</span></span>
<span class="line"></span></code></pre></div></li><li><p>Verify Docker Swarm status:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker node ls</span></span>
<span class="line"></span></code></pre></div></li><li><p>Try running commands manually:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker build -t localhost:5000/unitrack-backend ./UniTrackRemasterBackend</span></span>
<span class="line"><span style="color:#A6ACCD;">docker push localhost:5000/unitrack-backend</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F321}\uFE0F-performance-issues" tabindex="-1">\u{1F321}\uFE0F Performance Issues <a class="header-anchor" href="#\u{1F321}\uFE0F-performance-issues" aria-hidden="true">#</a></h2><h3 id="slow-application-response" tabindex="-1">Slow Application Response <a class="header-anchor" href="#slow-application-response" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Long load times</li><li>Timeout errors</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check container resources:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker stats</span></span>
<span class="line"></span></code></pre></div></li><li><p>Look for database performance issues:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker </span><span style="color:#82AAFF;">exec</span><span style="color:#A6ACCD;"> -it UniTrackRemaster.Database psql -U postgres -d UniTrackRemaster -c </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">SELECT * FROM pg_stat_activity</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div></li><li><p>Increase resources for services:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki"><code><span class="line"><span style="color:#F07178;">deploy</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">resources</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">limits</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#F07178;">cpus</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">1</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#F07178;">memory</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">1G</span></span>
<span class="line"></span></code></pre></div></li><li><p>Scale backend services:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service scale unitrack-stack_unitrack-backend=3</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F9EA}-development-environment-issues" tabindex="-1">\u{1F9EA} Development Environment Issues <a class="header-anchor" href="#\u{1F9EA}-development-environment-issues" aria-hidden="true">#</a></h2><h3 id="hot-reload-not-working" tabindex="-1">Hot Reload Not Working <a class="header-anchor" href="#hot-reload-not-working" aria-hidden="true">#</a></h3><p><strong>Symptoms:</strong></p><ul><li>Changes not reflected in browser</li><li>Need to manually restart containers</li></ul><p><strong>Solutions:</strong></p><ol><li><p>Check volume mounts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker-compose -f docker-compose.dev.yml config</span></span>
<span class="line"></span></code></pre></div></li><li><p>Enable polling:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># For frontend (in .env)</span></span>
<span class="line"><span style="color:#A6ACCD;">CHOKIDAR_USEPOLLING=true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># For backend</span></span>
<span class="line"><span style="color:#A6ACCD;">dotnet watch run --project YourProject.csproj</span></span>
<span class="line"></span></code></pre></div></li><li><p>Restart development containers:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker-compose -f docker-compose.dev.yml restart</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F4D1}-logs-and-diagnostics" tabindex="-1">\u{1F4D1} Logs and Diagnostics <a class="header-anchor" href="#\u{1F4D1}-logs-and-diagnostics" aria-hidden="true">#</a></h2><h3 id="collecting-diagnostic-information" tabindex="-1">Collecting Diagnostic Information <a class="header-anchor" href="#collecting-diagnostic-information" aria-hidden="true">#</a></h3><p>If you need to provide information for support:</p><ol><li><p>Collect Docker service status:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker stack services unitrack-stack </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> docker-status.txt</span></span>
<span class="line"></span></code></pre></div></li><li><p>Gather container logs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker service logs unitrack-stack_unitrack-backend </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> backend-logs.txt</span></span>
<span class="line"><span style="color:#A6ACCD;">docker service logs unitrack-stack_unitrack-frontend </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> frontend-logs.txt</span></span>
<span class="line"><span style="color:#A6ACCD;">docker service logs unitrack-stack_unitrack-db </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> db-logs.txt</span></span>
<span class="line"></span></code></pre></div></li><li><p>Check system resources:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker info </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> docker-info.txt</span></span>
<span class="line"><span style="color:#A6ACCD;">free -m </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> memory-info.txt</span></span>
<span class="line"><span style="color:#A6ACCD;">df -h </span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> disk-info.txt</span></span>
<span class="line"></span></code></pre></div></li><li><p>Create a support bundle:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">tar -czf unitrack-diagnostics.tar.gz </span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">.txt</span></span>
<span class="line"></span></code></pre></div></li></ol><h2 id="\u{1F4DE}-getting-help" tabindex="-1">\u{1F4DE} Getting Help <a class="header-anchor" href="#\u{1F4DE}-getting-help" aria-hidden="true">#</a></h2><p>If you continue to experience issues:</p><ol><li>Check the <a href="https://github.com/SpasMilenkov/UniTrackRemaster/issues" target="_blank" rel="noreferrer">GitHub Issues</a> for similar problems and solutions</li><li>File a new issue with detailed information about your problem</li></ol><p>Remember to include:</p><ul><li>Exact error messages</li><li>Steps to reproduce</li><li>Version information</li><li>Environment details</li></ul>`,90),t=[o];function i(p,c,r,d,u,h){return n(),a("div",null,t)}const y=s(l,[["render",i]]);export{C as __pageData,y as default};
